import { Children, type ReactNode } from 'react';

import { isSlot } from '../../../../../core/utils/is-slot.js';
import { TooltipSubheader } from '../section-components/TooltipSubheader.js';

export const iterateHeaderSlots = (children: ReactNode) => {
  const headerSlots: {
    header: ReactNode[];
    subHeader: ReactNode[];
  } = { header: [], subHeader: [] };

  Children.forEach(children, (child) => {
    if (isSlot(child, TooltipSubheader)) {
      headerSlots.subHeader.push(child.props.children);
      return;
    }
    headerSlots.header.push(child);
  });

  return headerSlots;
};
